from array import array
w,h=2400,1800
vals=array('H')
with open('/app/image.ppm','rt') as f:
    f.readline(); f.readline(); f.readline()
    for line in f: vals.extend(map(int,line.split()))
def px(x,y):
    i=(y*w+x)*3; return (vals[i],vals[i+1],vals[i+2])
# find first non-sky row by scanning center column
for y in range(h):
    r,g,b=px(w//2,y)
